import { WebSocketServer, WebSocket } from 'ws';

interface Live extends WebSocket { isAlive: boolean; }

const wss = new WebSocketServer({ port: 8080 });

wss.on('connection', (raw, req) => {
  const ws = raw as Live;
  ws.isAlive = true;

  // Peer answered our ping -> it is still there.
  ws.on('pong', () => { ws.isAlive = true; });

  ws.on('message', (data, isBinary) => {
    // Echo to every other open client (naive single-node broadcast).
    for (const client of wss.clients) {
      if (client !== ws && client.readyState === WebSocket.OPEN) {
        client.send(data, { binary: isBinary });
      }
    }
  });

  ws.on('close', (code) => console.log('closed', code));
  ws.send(JSON.stringify({ type: 'welcome' }));
});

// Heartbeat: every 30s, drop anyone who did not pong since last sweep.
const interval = setInterval(() => {
  for (const raw of wss.clients) {
    const ws = raw as Live;
    if (!ws.isAlive) { ws.terminate(); continue; }
    ws.isAlive = false;   // will be set true again by the pong handler
    ws.ping();
  }
}, 30_000);

wss.on('close', () => clearInterval(interval));

function connect(url: string): void {
  const ws = new WebSocket(url);
  let backoff = 1000;

  ws.onopen = () => { backoff = 1000; console.log('connected'); };

  ws.onmessage = (ev) => {
    const msg = JSON.parse(ev.data);
    render(msg);
  };

  ws.onclose = (ev) => {
    console.warn('closed', ev.code);
    // Exponential backoff with jitter, capped at 30s.
    const wait = Math.min(backoff, 30_000) * (0.5 + Math.random());
    backoff *= 2;
    setTimeout(() => connect(url), wait);
  };

  ws.onerror = () => ws.close();
}

