import express from 'express';
const app = express();

app.get('/events', (req, res) => {
  res.writeHead(200, {
    'Content-Type': 'text/event-stream',
    'Cache-Control': 'no-cache, no-transform',
    'Connection': 'keep-alive'
  });

  // Resume: replay events the client missed after a drop.
  const lastId = Number(req.headers['last-event-id'] ?? 0);
  for (const ev of getEventsSince(lastId)) {
    res.write(`id: ${ev.id}\n`);
    res.write(`event: ${ev.type}\n`);
    res.write(`data: ${JSON.stringify(ev.payload)}\n\n`);
  }

  const onEvent = (ev) => {
    res.write(`id: ${ev.id}\n`);
    res.write(`data: ${JSON.stringify(ev.payload)}\n\n`);
  };
  bus.on('event', onEvent);

  // Comment lines (starting with ':') act as keepalive pings.
  const ka = setInterval(() => res.write(': keepalive\n\n'), 15_000);

  req.on('close', () => { clearInterval(ka); bus.off('event', onEvent); });
});

