import { WebSocketServer, WebSocket } from 'ws';

interface Client extends WebSocket { isAlive: boolean; rooms: Set<string>; }

const wss = new WebSocketServer({ port: 8080 });
const rooms = new Map<string, Set<Client>>();

function join(ws: Client, room: string) {
  ws.rooms.add(room);
  if (!rooms.has(room)) rooms.set(room, new Set());
  rooms.get(room)!.add(ws);
}

function leaveAll(ws: Client) {
  for (const room of ws.rooms) {
    const set = rooms.get(room);
    if (set) { set.delete(ws); if (set.size === 0) rooms.delete(room); }
  }
  ws.rooms.clear();
}

function broadcast(room: string, payload: unknown) {
  const set = rooms.get(room);
  if (!set) return;
  const data = JSON.stringify(payload);
  for (const client of set) {
    if (client.readyState === WebSocket.OPEN) client.send(data);
  }
}

wss.on('connection', (raw) => {
  const ws = raw as Client;
  ws.isAlive = true;
  ws.rooms = new Set();
  ws.on('pong', () => { ws.isAlive = true; });

  ws.on('message', (buf) => {
    let m: any;
    try { m = JSON.parse(buf.toString()); } catch { return; }
    if (m.type === 'join' && typeof m.room === 'string') {
      join(ws, m.room);
      broadcast(m.room, { type: 'system', room: m.room, text: 'a user joined' });
    } else if (m.type === 'msg' && ws.rooms.has(m.room)) {
      broadcast(m.room, { type: 'msg', room: m.room, text: String(m.text) });
    }
  });

  ws.on('close', () => leaveAll(ws));
});

// Heartbeat: drop anyone who did not pong since the last sweep.
const hb = setInterval(() => {
  for (const raw of wss.clients) {
    const ws = raw as Client;
    if (!ws.isAlive) { leaveAll(ws); ws.terminate(); continue; }
    ws.isAlive = false;
    ws.ping();
  }
}, 30_000);

wss.on('close', () => clearInterval(hb));

import { WebSocketServer, WebSocket } from 'ws';
import { createClient } from 'redis';
import { randomUUID } from 'crypto';

interface Client extends WebSocket { rooms: Set<string>; }

const NODE_ID = randomUUID();
const wss = new WebSocketServer({ port: 8080 });
const rooms = new Map<string, Set<Client>>();

const pub = createClient();
const sub = pub.duplicate();
await pub.connect();
await sub.connect();

function localBroadcast(room: string, data: string) {
  const set = rooms.get(room);
  if (!set) return;
  for (const c of set) if (c.readyState === WebSocket.OPEN) c.send(data);
}

// One shared channel; payload names the room. (Shard by room for high scale.)
await sub.subscribe('chat', (raw) => {
  const env = JSON.parse(raw);
  if (env.origin === NODE_ID) return;         // we already delivered locally
  localBroadcast(env.room, JSON.stringify(env.msg));
});

function publish(room: string, msg: unknown) {
  const data = JSON.stringify(msg);
  localBroadcast(room, data);                  // deliver to our own members now
  pub.publish('chat', JSON.stringify({ origin: NODE_ID, room, msg }));
}

wss.on('connection', (raw) => {
  const ws = raw as Client;
  ws.rooms = new Set();
  ws.on('message', (buf) => {
    let m: any; try { m = JSON.parse(buf.toString()); } catch { return; }
    if (m.type === 'join') {
      ws.rooms.add(m.room);
      if (!rooms.has(m.room)) rooms.set(m.room, new Set());
      rooms.get(m.room)!.add(ws);
    } else if (m.type === 'msg' && ws.rooms.has(m.room)) {
      publish(m.room, { type: 'msg', room: m.room, text: String(m.text) });
    }
  });
  ws.on('close', () => {
    for (const r of ws.rooms) rooms.get(r)?.delete(ws);
    ws.rooms.clear();
  });
});
